import{_ as i,o as a,c as e,a2 as o}from"./chunks/framework.BWuWLRhz.js";const _=JSON.parse('{"title":"利多星项目待补充信息清单","description":"","frontmatter":{},"headers":[],"relativePath":"docs/liduoxing-missing-info.md","filePath":"docs/liduoxing-missing-info.md"}'),r={name:"docs/liduoxing-missing-info.md"};function t(u,l,n,d,s,h){return a(),e("div",null,[...l[0]||(l[0]=[o('<h1 id="利多星项目待补充信息清单" tabindex="-1">利多星项目待补充信息清单 <a class="header-anchor" href="#利多星项目待补充信息清单" aria-label="Permalink to &quot;利多星项目待补充信息清单&quot;">​</a></h1><p>本文档用于后续补齐利多星金融数据产品专题。当前网站页面已经先按现有资料整理出文字版，后续需要补充个人角色边界、成果数据和可公开素材。</p><h2 id="_1-整体信息" tabindex="-1">1. 整体信息 <a class="header-anchor" href="#_1-整体信息" aria-label="Permalink to &quot;1. 整体信息&quot;">​</a></h2><p>需要确认：</p><ul><li>利多星任职时间或项目覆盖时间段。</li><li>你在利多星的正式岗位名称。</li><li>是否可以写“主导”： <ul><li>私享家 BI 是否由你主导需求和看板结构？</li><li>埋点治理是否由你主导方法论和验数？</li><li>AI 客诉是否由你主导风险场景和产品框架？</li><li>用户标签是否由你主导标签体系和数据集方案？</li><li>股民保护 BI 是否由你主导 BI 需求和原型？</li></ul></li><li>哪些项目已经上线，哪些处于方案 / 原型 / 进行中状态。</li><li>是否有管理层、业务方或跨部门协作背书可以公开表达。</li></ul><h2 id="_2-私享家-bi-数据看板" tabindex="-1">2. 私享家 BI 数据看板 <a class="header-anchor" href="#_2-私享家-bi-数据看板" aria-label="Permalink to &quot;2. 私享家 BI 数据看板&quot;">​</a></h2><p>当前页面已写：</p><ul><li>总览驾驶舱、策略收益、客户价值、产品分析、客服 / 投顾服务五大模块。</li><li>P0 优先级：策略收益、案例池选股、总览驾驶舱。</li><li>核心难点：服务周期、企微与派工关系、群发与单聊、策略快照、跨端行为。</li></ul><p>需要补充：</p><ul><li>项目周期：从哪月开始，到哪月完成第一版。</li><li>看板是否真实上线到观远 BI 或内部 BI 系统。</li><li>是否有实际使用角色：老板 / 管理层 / 投研 / 客服 / 投顾 / 运营。</li><li>可以公开的成果数据： <ul><li>看板模块数量。</li><li>指标数量。</li><li>覆盖策略数量或客户量级，是否需要模糊化。</li><li>业务使用频率或复盘场景。</li></ul></li><li>可公开素材： <ul><li>脱敏看板截图。</li><li>字段口径表局部截图。</li><li>原型 demo 截图。</li></ul></li></ul><h2 id="_3-数据埋点治理" tabindex="-1">3. 数据埋点治理 <a class="header-anchor" href="#_3-数据埋点治理" aria-label="Permalink to &quot;3. 数据埋点治理&quot;">​</a></h2><p>当前页面已写：</p><ul><li>覆盖 APP / 小程序 / PC / H5。</li><li>五阶段 SOP：盘点、标准、检查、修复、上线监控。</li><li>A/B/C/D 质量分级。</li><li>14 天全量数据、7 个重点事件验数。</li><li>宽表 v2、URL 清洗、ID 补全。</li></ul><p>需要补充：</p><ul><li>是否可以公开写“14 天全量分析”和“7 个事件”。</li><li>是否可以公开部分事件名称，例如系统通知栏、案例股详情、尊享直播汇。</li><li>是否可以公开部分 PV / UV 数字，还是全部改成“万级 PV / 千级 UV”。</li><li>这套 SOP 后续是否被团队采用。</li><li>是否推动开发 / 数仓修复了哪些问题。</li><li>可公开素材： <ul><li>字段质量分析报告截图。</li><li>埋点验收 SOP 截图。</li><li>事件质量评估报告截图。</li><li>宽表清洗规则截图。</li></ul></li></ul><h2 id="_4-ai-客诉与风控体系" tabindex="-1">4. AI 客诉与风控体系 <a class="header-anchor" href="#_4-ai-客诉与风控体系" aria-label="Permalink to &quot;4. AI 客诉与风控体系&quot;">​</a></h2><p>当前页面已写：</p><ul><li>10 类风险场景。</li><li>基于多月外诉复盘形成语义和场景归因。</li><li>关键词体系和风险识别闭环。</li><li>从识别、匹配、分级、触达到复盘的流程。</li></ul><p>需要补充：</p><ul><li>项目周期：从 2026 年 4 月开始后，当前状态是什么。</li><li>是否已有系统落地，还是方案 / 需求 / 原型阶段。</li><li>“月均外诉量控制目标”是否可以公开，当前页面暂未写具体目标。</li><li>历史外诉案例数量是否可以公开，目前页面只写“百件级复盘”。</li><li>是否与智多星 / 玉衡星后台有关，需要怎样表述。</li><li>可公开素材： <ul><li>风险流程图。</li><li>风险标签体系。</li><li>脱敏后的场景分类表。</li><li>不含客户信息的系统原型截图。</li></ul></li></ul><h2 id="_5-用户分层与客户经营分析" tabindex="-1">5. 用户分层与客户经营分析 <a class="header-anchor" href="#_5-用户分层与客户经营分析" aria-label="Permalink to &quot;5. 用户分层与客户经营分析&quot;">​</a></h2><p>当前页面已写：</p><ul><li>生命周期分层：1.0 / 2.0 / 3.0 / 流失预警。</li><li>标签维度：基础、行为、价值、产品适配、风险、忠诚度。</li><li>数据集：客户服务宽表、用户活跃宽表。</li><li>ID 映射：埋点用户 -&gt; 账户用户 -&gt; 订单客户。</li></ul><p>需要补充：</p><ul><li>标签体系是否已落地，还是分析框架阶段。</li><li>“120 天养护周期、15 天升级窗口”等规则是否可以公开。</li><li>客户服务宽表、活跃宽表是否进入 BI 或数仓开发。</li><li>是否可以写订单 / 客户量级；如敏感则只写“多年历史订单与客户数据”。</li><li>可公开素材： <ul><li>标签体系 xmind / 表格截图。</li><li>客户生命周期分析报告截图。</li><li>ID 映射链路图。</li><li>宽表字段脱敏截图。</li></ul></li></ul><h2 id="_6-股民保护-bi-看板" tabindex="-1">6. 股民保护 BI 看板 <a class="header-anchor" href="#_6-股民保护-bi-看板" aria-label="Permalink to &quot;6. 股民保护 BI 看板&quot;">​</a></h2><p>当前页面已写：</p><ul><li>投资者权益维护业务。</li><li>公域曝光、资源进线、私域咨询、客户分类、签约、维权标的。</li><li>总览、渠道、公域、转化漏斗、标的、运营复盘模块。</li><li>重点口径：资源、A 类客户、维权股、标的金额、营收估算。</li></ul><p>需要补充：</p><ul><li>你参与项目的准确时间段。</li><li>看板是否上线，还是 demo / 原型 / 需求阶段。</li><li>可公开的成果： <ul><li>dashboard 数量。</li><li>指标数量。</li><li>是否服务管理层月报或业务复盘。</li></ul></li><li>“2025 年 4 月项目开始”是否可以写。</li><li>可公开素材： <ul><li>dashboard-overview / channel / operation 的脱敏截图。</li><li>业务流程图。</li><li>数据口径表。</li><li>月报截图。</li></ul></li></ul><h2 id="_7-页面后续优化方向" tabindex="-1">7. 页面后续优化方向 <a class="header-anchor" href="#_7-页面后续优化方向" aria-label="Permalink to &quot;7. 页面后续优化方向&quot;">​</a></h2><p>后续建议分三步：</p><ol><li>先补角色边界和项目状态，让页面表达更真实。</li><li>再补可公开的成果数据，让页面更有说服力。</li><li>最后补脱敏截图和局部表格，避免纯文字页面显得抽象。</li></ol><p>当前页面已避免公开内部账号、客户信息、完整 SQL、经营金额和敏感个案。后续补图时也建议优先选择脱敏流程图、局部指标框架和可公开原型，不直接展示完整内部系统。</p>',34)])])}const c=i(r,[["render",t]]);export{_ as __pageData,c as default};
